import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.uucRfDOW.js";const u=JSON.parse('{"title":"Performance: Fast Authority Checks","description":"","frontmatter":{},"headers":[],"relativePath":"bitmasking.md","filePath":"bitmasking.md"}'),o={name:"bitmasking.md"};function r(n,e,l,h,d,c){return a(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="performance-fast-authority-checks" tabindex="-1">Performance: Fast Authority Checks <a class="header-anchor" href="#performance-fast-authority-checks" aria-label="Permalink to &quot;Performance: Fast Authority Checks&quot;">​</a></h1><p>OmniGuard is built to be snappy and efficient. It uses a simple technique called <strong>Bitmasking</strong> to make authorization checks as fast as possible, so your application stays responsive.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Instead of using long lists of names, OmniGuard assigns each permission a simple number.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Permission</th><th style="text-align:left;">Index</th></tr></thead><tbody><tr><td style="text-align:left;"><code>user.view</code></td><td style="text-align:left;">0</td></tr><tr><td style="text-align:left;"><code>user.create</code></td><td style="text-align:left;">1</td></tr><tr><td style="text-align:left;"><code>user.edit</code></td><td style="text-align:left;">2</td></tr></tbody></table><hr><h2 id="speedy-comparisons" tabindex="-1">Speedy Comparisons <a class="header-anchor" href="#speedy-comparisons" aria-label="Permalink to &quot;Speedy Comparisons&quot;">​</a></h2><p>When a user logs in, OmniGuard combines their permissions into a single, small piece of data. This allows the computer to perform checks almost instantly.</p><p>It&#39;s a bit like a row of light switches—OmniGuard can check if the right switch is &#39;on&#39; in a single step, rather than looking through a long list of papers.</p><hr><h2 id="shared-hosting-friendly" tabindex="-1">Shared Hosting Friendly <a class="header-anchor" href="#shared-hosting-friendly" aria-label="Permalink to &quot;Shared Hosting Friendly&quot;">​</a></h2><p>This method is specifically designed to be light on your server&#39;s memory. This is perfect if you are on a budget shared hosting plan with limited resources:</p><ol><li><strong>Light Memory</strong>: Because it uses simple numbers instead of long strings of text, it takes up very little space.</li><li><strong>Fast</strong>: Your server doesn&#39;t have to work hard to check permissions, which helps keep your page loads fast.</li></ol><hr><h2 id="automatic-updates" tabindex="-1">Automatic Updates <a class="header-anchor" href="#automatic-updates" aria-label="Permalink to &quot;Automatic Updates&quot;">​</a></h2><p>OmniGuard is smart enough to know when you&#39;ve changed something. If you add a new role or permission, it will automatically refresh this speed-optimized data for you on the next request.</p><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Learn how OmniGuard can help you with security in the <strong><a href="./security.html">Security Helpers Guide</a></strong>.</p>',19)])])}const m=t(o,[["render",r]]);export{u as __pageData,m as default};
